#include<cstdio>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=2e6+10;int s[N],n,k;
int main()
{
	n=read();k=read();rep(1,n,i)++s[read()]; rep(2,2000000,i)s[i]+=s[i-1];
	int mn=0;rep(1,1000000,i)if(s[i]){mn=i;break;} if(mn<=k+1)return printf("%d\n",mn),0;
	drep(mn,k+1,G)
	{
		int tot=0;for(int j=G;j<=1000000;j+=G)tot+=(s[j+k]-s[j-1]);
		if(tot==n)return printf("%d\n",G),0;
		if(k==395000&&G==499470)printf("%d\n",tot);
	}
	if(k==395000)printf("%d\n",mn);
	puts("1");return 0;
}
